import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Domande Frequenti per Giocatori (FAQ)","description":"Domande frequenti riguardanti Fabric per giocatori e admin di server.","frontmatter":{"title":"Domande Frequenti per Giocatori (FAQ)","description":"Domande frequenti riguardanti Fabric per giocatori e admin di server.","search":false,"files":[]},"headers":[],"relativePath":"it_it/1.20.4/players/faq.md","filePath":"versions/1.20.4/translated/it_it/players/faq.md","lastUpdated":1739538073000}`);var a={name:`it_it/1.20.4/players/faq.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Domande Frequenti per Giocatori (FAQ) <a class="header-anchor" href="#h1" aria-label="Permalink to “Domande Frequenti per Giocatori (FAQ)”">​</a></h1><p>Ci sono molte domande che vengono poste di frequente, quindi ne abbiamo compilato una lista qui.</p><h2 id="domande-generali" tabindex="-1">Domande Generali <a class="header-anchor" href="#domande-generali" aria-label="Permalink to “Domande Generali”">​</a></h2><h3 id="quali-versioni-di-minecraft-supporta-fabric" tabindex="-1">Quali Versioni di Minecraft Supporta Fabric? <a class="header-anchor" href="#quali-versioni-di-minecraft-supporta-fabric" aria-label="Permalink to “Quali Versioni di Minecraft Supporta Fabric?”">​</a></h3><p>Ufficialmente, Fabric supporta tutte le versioni di Minecraft a partire da snapshot <code>18w43b</code> e seguenti, e dalla release <code>1.14</code> e superiori.</p><h3 id="dove-posso-scaricare-le-mod-fabric-pubblicate" tabindex="-1">Dove Posso Scaricare le Mod Fabric Pubblicate? <a class="header-anchor" href="#dove-posso-scaricare-le-mod-fabric-pubblicate" aria-label="Permalink to “Dove Posso Scaricare le Mod Fabric Pubblicate?”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Dovresti sempre controllare che le mod provengano da una fonte affidabile. Dai un occhiata alla guida <a href="./finding-mods">Trovare Mod Affidabili</a> per più informazioni.</p></div><p>La maggior parte degli autori pubblica le loro mod su <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> e <a href="https://www.curseforge.com/minecraft/search?class=mc-mods&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a>, anche se altri potrebbero aver deciso di caricarle sui loro siti personali o su altre piattaforme come le repository di GitHub.</p><h3 id="dove-posso-trovare-modpack-fabric-prefabbricati" tabindex="-1">Dove Posso Trovare Modpack Fabric Prefabbricati? <a class="header-anchor" href="#dove-posso-trovare-modpack-fabric-prefabbricati" aria-label="Permalink to “Dove Posso Trovare Modpack Fabric Prefabbricati?”">​</a></h3><p>Puoi trovare modpack Fabric prefabbricati su varie piattaforme, come:</p><ul><li><a href="https://modrinth.com/modpacks?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a></li><li><a href="https://www.curseforge.com/minecraft/search?class=modpacks&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a></li><li><a href="https://www.feed-the-beast.com/ftb-app" target="_blank" rel="noreferrer">Feed The Beast</a></li><li><a href="https://www.technicpack.net/modpacks" target="_blank" rel="noreferrer">Technic</a></li></ul>`,11)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};